insert into public.exercises (id, name, muscle_group, equipment, target, secondary_muscles, instructions, gif_path) values
  ('db-0764', 'smith reverse-grip press', 'Chest', 'Smith Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the height of the smith machine bar to chest level.','Stand facing the bar with your feet shoulder-width apart.','Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart.','Step back and position yourself with a slight bend in your knees.','Keep your chest up and core engaged throughout the exercise.','Lower the bar towards your chest, keeping your elbows tucked in.','Pause for a moment at the bottom, then push the bar back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'zK8Fu1W'),
  ('db-1395', 'smith seated one leg calf raise', 'Legs', 'Smith Machine', 'calves', ARRAY['hamstrings']::text[], ARRAY['Sit on the machine with your back against the pad and your feet on the footrest.','Place one leg on the footrest and keep the other leg off the footrest.','Using your calf muscles, raise your heel as high as possible.','Pause for a moment at the top, then slowly lower your heel back down to the starting position.','Repeat for the desired number of repetitions, then switch legs and repeat.']::text[], '0S75mYG'),
  ('db-0765', 'smith seated shoulder press', 'Shoulders', 'Smith Machine', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Adjust the seat height so that the handles are at shoulder level.','Sit on the machine with your back against the pad and your feet flat on the floor.','Grasp the handles with an overhand grip and lift them off the supports, extending your arms fully.','Lower the handles down to shoulder level, keeping your elbows slightly bent.','Press the handles up overhead until your arms are fully extended.','Pause for a moment at the top, then slowly lower the handles back down to shoulder level.','Repeat for the desired number of repetitions.']::text[], 'xUwnBMT'),
  ('db-1426', 'smith seated wrist curl', 'Arms', 'Smith Machine', 'forearms', ARRAY['biceps','brachialis']::text[], ARRAY['Sit on a bench in front of a Smith machine with your feet flat on the ground.','Grasp the barbell with an underhand grip, hands shoulder-width apart.','Rest your forearms on your thighs, allowing your wrists to hang off.','Slowly curl your wrists upward, bringing the barbell towards your forearms.','Pause for a moment at the top, then slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'B6dAO1t'),
  ('db-0766', 'smith shoulder press', 'Shoulders', 'Smith Machine', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Adjust the seat height and position yourself on the smith machine with your feet shoulder-width apart.','Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.','Lift the bar off the rack and position it at shoulder level, with your elbows bent and palms facing forward.','Press the bar upward until your arms are fully extended overhead.','Pause for a moment at the top, then slowly lower the bar back down to shoulder level.','Repeat for the desired number of repetitions.']::text[], '903mzG8'),
  ('db-0767', 'smith shrug', 'Back', 'Smith Machine', 'traps', ARRAY['shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.','Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.','Keep your arms straight and your shoulders relaxed.','Lift your shoulders up towards your ears, squeezing your traps at the top.','Hold for a moment, then slowly lower your shoulders back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'OUQ0ZyW'),
  ('db-0768', 'smith single leg split squat', 'Legs', 'Smith Machine', 'quads', ARRAY['glutes','hamstrings']::text[], ARRAY['Stand in front of the smith machine with your feet shoulder-width apart.','Place one foot behind you on a bench or step, with your toes pointing forward.','Hold onto the smith machine bar for stability.','Bend your front knee and lower your body down into a lunge position, keeping your back straight.','Pause for a moment at the bottom, then push through your front heel to return to the starting position.','Repeat for the desired number of repetitions, then switch legs.']::text[], 'wWFspEi'),
  ('db-0769', 'smith sprint lunge', 'Legs', 'Smith Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Set up the smith machine with the barbell at hip height.','Stand facing away from the machine with your feet shoulder-width apart.','Step back with your right foot and place it on the barbell, resting the top of your foot on the bar.','Bend your left knee and lower your body into a lunge position, keeping your back straight.','Push through your left heel to return to the starting position.','Repeat on the other side, stepping back with your left foot.','Continue alternating sides for the desired number of repetitions.']::text[], 'HsjbB1z'),
  ('db-0770', 'smith squat', 'Legs', 'Smith Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Set up the smith machine with the barbell at an appropriate height for your squat.','Stand with your feet shoulder-width apart, toes slightly turned out.','Position yourself under the barbell, resting it on your upper traps and shoulders.','Grip the barbell with a wide grip, slightly wider than shoulder-width apart.','Engage your core and unrack the barbell, stepping back to clear the rack.','Keeping your chest up and back straight, initiate the squat by bending at the hips and knees.','Lower your body until your thighs are parallel to the ground or slightly below.','Pause for a moment at the bottom, then drive through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'jFtipLl'),
  ('db-0771', 'smith standing back wrist curl', 'Arms', 'Smith Machine', 'forearms', ARRAY['biceps','triceps']::text[], ARRAY['Stand facing the smith machine with your feet shoulder-width apart.','Grasp the barbell with an overhand grip, hands shoulder-width apart.','Keep your back straight and your elbows close to your body.','Slowly curl your wrists upwards, bringing the barbell towards your body.','Pause for a moment at the top, then slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'hfmQ0Tz'),
  ('db-0772', 'smith standing behind head military press', 'Shoulders', 'Smith Machine', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Adjust the seat height of the smith machine so that the bar is at shoulder level.','Stand with your feet shoulder-width apart and your knees slightly bent.','Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.','Lift the bar off the rack and step back, maintaining a stable stance.','Position the bar behind your head, resting on your upper traps.','Keep your core engaged and your chest lifted throughout the exercise.','Press the bar overhead by extending your arms, fully straightening them.','Pause briefly at the top of the movement, then slowly lower the bar back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ht8xDrP'),
  ('db-0773', 'smith standing leg calf raise', 'Legs', 'Smith Machine', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Adjust the smith machine bar to a height that allows you to stand with your feet flat on the ground and your shoulders under the bar.','Position yourself under the bar with your feet shoulder-width apart and your toes pointing forward.','Place your hands on the bar for stability.','Engage your calves and slowly raise your heels off the ground, lifting your body up onto your toes.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '6MaEjVA'),
  ('db-0774', 'smith standing military press', 'Shoulders', 'Smith Machine', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.','Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.','Lift the barbell off the rack and bring it down to shoulder level, with your palms facing forward.','Press the barbell upward until your arms are fully extended overhead.','Pause for a moment at the top, then slowly lower the barbell back down to shoulder level.','Repeat for the desired number of repetitions.']::text[], 'jjUPrze'),
  ('db-3142', 'smith sumo squat', 'Legs', 'Smith Machine', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Set up the smith machine with the barbell at hip height.','Stand with your feet wider than shoulder-width apart, toes pointing outwards.','Position yourself under the barbell, resting it on your upper back and shoulders.','Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees.','Lower yourself until your thighs are parallel to the ground, or as low as you can comfortably go.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'dzz6BiV'),
  ('db-1396', 'smith toe raise', 'Legs', 'Smith Machine', 'calves', ARRAY['ankles','shins']::text[], ARRAY['Adjust the smith machine bar to a height that allows you to comfortably stand with your feet flat on the ground.','Position yourself under the bar with your shoulders directly below it and your feet shoulder-width apart.','Place the balls of your feet on a raised platform or weight plates, with your heels hanging off the edge.','Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.','Engage your core and keep your back straight throughout the exercise.','Slowly raise your heels as high as possible, lifting your body weight onto the balls of your feet.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Y4QlY8z'),
  ('db-0775', 'smith upright row', 'Shoulders', 'Smith Machine', 'delts', ARRAY['traps','biceps']::text[], ARRAY['Stand with your feet shoulder-width apart, facing the smith machine.','Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.','Keep your back straight and your core engaged.','Pull the barbell up towards your chin, leading with your elbows.','Pause for a moment at the top, then slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '1DN3iz4'),
  ('db-1308', 'smith wide grip bench press', 'Chest', 'Smith Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the bench to a comfortable position on the smith machine.','Lie down on the bench with your feet flat on the ground.','Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.','Unrack the barbell and lower it slowly towards your chest, keeping your elbows out to the sides.','Pause for a moment when the barbell touches your chest.','Push the barbell back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'zoOvPcx'),
  ('db-1309', 'smith wide grip decline bench press', 'Chest', 'Smith Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the decline bench to the desired angle.','Lie down on the bench with your feet secured under the foot pads.','Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.','Unrack the barbell and lower it slowly towards your chest, keeping your elbows pointed outwards.','Pause for a moment when the barbell touches your chest.','Push the barbell back up to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'wi2H9QX'),
  ('db-0776', 'snatch pull', 'Legs', 'Barbell', 'quads', ARRAY['hamstrings','glutes','calves']::text[], ARRAY['Stand with your feet shoulder-width apart and the barbell on the ground in front of you.','Bend your knees and hinge at the hips to lower into a squat position, gripping the barbell with an overhand grip.','Keep your back straight and chest up as you drive through your heels to lift the barbell off the ground, extending your hips and knees.','As the barbell reaches hip level, explosively pull it upwards, shrugging your shoulders and pulling your elbows high and to the sides.','As the barbell reaches its highest point, quickly drop underneath it, pulling yourself into a deep squat position.','Catch the barbell overhead with your arms fully extended and your knees bent.','Stand up by extending your hips and knees, keeping the barbell overhead.','Lower the barbell back down to the starting position by reversing the movement.','Repeat for the desired number of repetitions.']::text[], 'dG5Smob'),
  ('db-0777', 'spell caster', 'Core', 'Dumbbell', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in one hand.','Bend your knees slightly and hinge forward at the waist, keeping your back straight.','Extend your arm with the dumbbell towards the opposite foot, rotating your torso as you do so.','Return to the starting position and repeat on the other side.','Continue alternating sides for the desired number of repetitions.']::text[], 'p9cCe2r'),
  ('db-1362', 'sphinx', 'Back', 'Body Weight', 'spine', ARRAY['glutes','hamstrings']::text[], ARRAY['Lie face down on the ground with your forearms flat on the floor, elbows directly under your shoulders.','Engage your core and lift your chest off the ground, keeping your forearms and toes on the floor.','Hold this position for a few seconds, making sure to keep your neck in a neutral position.','Slowly lower your chest back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'DIVyqrU'),
  ('db-0778', 'spider crawl push up', 'Legs', 'Body Weight', 'glutes', ARRAY['core','chest','shoulders']::text[], ARRAY['Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.','Bring your right knee towards your right elbow, keeping it off the ground.','As you bring your right knee back, simultaneously lower your body towards the ground by bending your elbows.','Push back up to the starting position and repeat with your left knee towards your left elbow.','Continue alternating sides for the desired number of repetitions.']::text[], 'P9GFBME'),
  ('db-1363', 'spine stretch', 'Back', 'Body Weight', 'spine', ARRAY['hamstrings','glutes']::text[], ARRAY['Sit on the ground with your legs extended in front of you.','Place your hands on the ground behind you, fingers pointing towards your body.','Engage your core and slowly lean back, keeping your back straight.','Continue leaning back until you feel a stretch in your spine.','Hold the stretch for a few seconds, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'JbC2iaV'),
  ('db-2329', 'spine twist', 'Core', 'Body Weight', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Sit on the ground with your legs extended in front of you.','Bend your knees and place your feet flat on the ground, hip-width apart.','Place your hands behind your head with your elbows pointing outwards.','Engage your abs and slowly twist your torso to the right, bringing your right elbow towards your left knee.','Pause for a moment at the end of the twist, then slowly return to the starting position.','Repeat the twist to the left side, bringing your left elbow towards your right knee.','Continue alternating sides for the desired number of repetitions.']::text[], '2jl9K55'),
  ('db-2368', 'split squats', 'Legs', 'Body Weight', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart.','Take a step forward with one foot and place it about two feet in front of the other foot.','Lower your body by bending your knees and hips, keeping your back straight.','Continue lowering until your front thigh is parallel to the ground, and your back knee is hovering just above the ground.','Pause for a moment, then push through your front heel to return to the starting position.','Repeat for the desired number of repetitions, then switch legs and repeat.']::text[], '9E25EOx'),
  ('db-0786', 'squat jerk', 'Legs', 'Barbell', 'quads', ARRAY['glutes','hamstrings','calves','core']::text[], ARRAY['Start with the barbell resting on your shoulders, with your feet shoulder-width apart.','Lower your body into a squat position, keeping your chest up and your knees tracking over your toes.','As you reach the bottom of the squat, explosively drive through your legs and push the barbell overhead.','As the barbell reaches its peak, quickly drop into a split position, with one foot forward and one foot back.','Catch the barbell overhead with your arms fully extended and your back knee slightly touching the ground.','Stand up from the split position, bringing your feet back together.','Lower the barbell back to your shoulders and repeat for the desired number of repetitions.']::text[], 'IMRsOCn'),
  ('db-1705', 'squat on bosu ball', 'Legs', 'Bosu Ball', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Place the bosu ball on the ground with the flat side up.','Stand with your feet shoulder-width apart and position yourself on top of the bosu ball.','Lower your body down by bending your knees and hips, as if sitting back into a chair.','Keep your chest up and your weight on your heels.','Lower yourself until your thighs are parallel to the ground.','Pause for a moment, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'T2fA5Ir'),
  ('db-1685', 'squat to overhead reach', 'Legs', 'Body Weight', 'quads', ARRAY['glutes','hamstrings','core']::text[], ARRAY['Stand with your feet shoulder-width apart and toes slightly turned out.','Lower your body down into a squat position by bending your knees and pushing your hips back.','As you come up from the squat, extend your arms overhead, reaching towards the ceiling.','Return to the starting position by lowering your arms and bending your knees to squat down again.','Repeat for the desired number of repetitions.']::text[], 'QChZi3x'),
  ('db-1686', 'squat to overhead reach with twist', 'Legs', 'Body Weight', 'quads', ARRAY['glutes','hamstrings','core']::text[], ARRAY['Stand with your feet shoulder-width apart and toes slightly turned out.','Lower your body into a squat position by bending your knees and pushing your hips back.','As you come up from the squat, raise your arms overhead and twist your torso to one side.','Return to the starting position and repeat the squat, this time twisting your torso to the opposite side.','Continue alternating sides with each squat repetition.']::text[], '5BZHW9s'),
  ('db-2297', 'stability ball crunch (full range hands behind head)', 'Core', 'Stability Ball', 'abs', ARRAY['hip flexors']::text[], ARRAY['Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.','Place your hands behind your head with your elbows pointing outwards.','Engaging your abs, slowly curl your upper body forward, bringing your chest towards your knees.','Pause for a moment at the top, then slowly lower your upper body back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Gn5FwYT'),
  ('db-3291', 'stalder press', 'Arms', 'Body Weight', 'triceps', ARRAY['shoulders','core']::text[], ARRAY['Start by standing with your feet shoulder-width apart and your arms extended overhead.','Bend your knees slightly and engage your core.','Lower your body down into a squat position while keeping your arms extended overhead.','As you squat down, press your arms down towards the ground, engaging your triceps.','Pause for a moment at the bottom of the squat, then push through your heels to stand back up while simultaneously raising your arms back overhead.','Repeat for the desired number of repetitions.']::text[], 'zd4P4B2'),
  ('db-3669', 'standing archer', 'Back', 'Body Weight', 'upper back', ARRAY['shoulders','biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.','Extend your arms straight out in front of you at shoulder height, parallel to the ground.','Rotate your torso to the right, keeping your arms extended and your back straight.','As you rotate, extend your right arm forward and your left arm back, mimicking the motion of drawing a bowstring.','Hold the position for a moment, then return to the starting position.','Repeat the motion, this time rotating your torso to the left and extending your left arm forward and your right arm back.','Continue alternating sides for the desired number of repetitions.']::text[], 'JF8AkMX'),
  ('db-0788', 'standing behind neck press', 'Shoulders', 'Barbell', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart and hold the barbell behind your neck with an overhand grip.','Keep your back straight and core engaged.','Press the barbell overhead by extending your arms, fully extending your elbows.','Pause for a moment at the top, then slowly lower the barbell back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'xDh0lJr'),
  ('db-1490', 'standing calf raise (on a staircase)', 'Legs', 'Body Weight', 'calves', ARRAY['ankles','feet']::text[], ARRAY['Stand on the edge of a step or a sturdy platform with your heels hanging off and your toes on the step.','Hold onto a railing or wall for balance if needed.','Slowly raise your heels as high as possible, lifting your body weight onto the balls of your feet.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '6HmFgmx'),
  ('db-1397', 'standing calves', 'Legs', 'Body Weight', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Stand with your feet shoulder-width apart, toes pointing forward.','Raise your heels off the ground as high as possible, standing on your toes.','Hold the position for a moment, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'XIHEoCG'),
  ('db-1398', 'standing calves calf stretch', 'Legs', 'Body Weight', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Stand facing a wall or sturdy object, about an arm''s length away.','Place your hands on the wall or object at shoulder height.','Step back with one foot, keeping your heel flat on the ground.','Bend your front knee slightly and lean forward, keeping your back leg straight.','You should feel a stretch in your calf muscle.','Hold the stretch for 20-30 seconds.','Repeat on the other leg.']::text[], 'qOKcgVP'),
  ('db-1599', 'standing hamstring and calf stretch with strap', 'Legs', 'Rope', 'hamstrings', ARRAY['calves']::text[], ARRAY['Stand upright with your feet shoulder-width apart.','Hold the strap with both hands and place it around the ball of your foot.','Keep your leg straight and slowly lean forward from your hips, keeping your back straight.','Feel the stretch in your hamstring and calf muscles.','Hold the stretch for 20-30 seconds.','Release the stretch and repeat with the other leg.','Repeat for the desired number of repetitions.']::text[], 'xTjr103'),
  ('db-0794', 'standing lateral stretch', 'Back', 'Body Weight', 'lats', ARRAY['shoulders','obliques']::text[], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.','Extend your arms straight out to the sides, parallel to the ground.','Slowly lean your upper body to one side, feeling a stretch in your side and lats.','Hold the stretch for 15-30 seconds.','Return to the starting position and repeat on the other side.','Repeat for the desired number of repetitions.']::text[], '1jXLYEw'),
  ('db-1364', 'standing pelvic tilt', 'Back', 'Body Weight', 'spine', ARRAY['abdominals']::text[], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.','Place your hands on your hips or let them hang by your sides.','Engage your core muscles and tilt your pelvis forward, pushing your lower back towards the wall behind you.','Hold the position for a few seconds, then release and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'cuKYxhu'),
  ('db-0795', 'standing single leg curl', 'Legs', 'Body Weight', 'hamstrings', ARRAY['glutes']::text[], ARRAY['Stand with your feet hip-width apart and your hands on your hips.','Shift your weight onto your left leg and lift your right foot off the ground, bending your knee.','Slowly curl your right heel towards your glutes, squeezing your hamstring.','Pause for a moment at the top, then slowly lower your right foot back down to the starting position.','Repeat for the desired number of repetitions, then switch legs.']::text[], 'C5jncD2'),
  ('db-0796', 'standing wheel rollerout', 'Core', 'Wheel Roller', 'abs', ARRAY['lower back','shoulders']::text[], ARRAY['Start by standing tall with your feet shoulder-width apart and the wheel roller in front of you.','Bend at your waist and slowly roll the wheel forward, keeping your back straight and your core engaged.','Continue rolling forward until you feel a stretch in your abs and your body is extended as far as possible.','Pause for a moment, then slowly roll the wheel back towards your body, returning to the starting position.','Repeat for the desired number of repetitions.']::text[], 'KtRomty'),
  ('db-3223', 'star jump (male)', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart and your arms by your sides.','Bend your knees slightly and jump up explosively.','As you jump, spread your legs and extend your arms out to the sides, forming a star shape with your body.','Land softly on the balls of your feet with your knees slightly bent.','Repeat for the desired number of repetitions.']::text[], 'HtfCpfi'),
  ('db-2138', 'stationary bike run v. 3', 'Other', 'Stationary Bike', 'cardiovascular system', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Adjust the seat height and position to ensure proper alignment.','Place your feet on the pedals and secure them with the straps if available.','Start pedaling at a comfortable pace.','Maintain a steady rhythm and increase the resistance as desired.','Engage your core muscles to maintain stability and proper posture.','Continue pedaling for the desired duration of your workout.','Gradually decrease the resistance and slow down before coming to a complete stop.','Stretch your legs and cool down after the workout.']::text[], 'H1PESYI'),
  ('db-0798', 'stationary bike walk', 'Other', 'Leverage Machine', 'cardiovascular system', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Adjust the seat height and position on the stationary bike to ensure proper alignment.','Place your feet on the pedals and secure them with the straps if available.','Start pedaling at a comfortable pace, keeping your back straight and core engaged.','Maintain a steady rhythm and increase the resistance level if desired.','Continue pedaling for the desired duration of your cardio workout.','Cool down by gradually reducing your pace and resistance level.','Stretch your leg muscles after the workout to prevent tightness and promote recovery.']::text[], 'a8VDgLw'),
  ('db-3314', 'straddle maltese', 'Core', 'Body Weight', 'abs', ARRAY['shoulders','chest']::text[], ARRAY['Start by hanging from a pair of rings with your arms fully extended and your body in a straight line.','Spread your legs wide apart, forming a straddle position.','Engage your core and slowly lower your body until your arms are parallel to the ground.','Hold this position for a few seconds, then push yourself back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'HfqciZF'),
  ('db-3298', 'straddle planche', 'Core', 'Body Weight', 'abs', ARRAY['shoulders','triceps','chest']::text[], ARRAY['Start in a push-up position with your hands shoulder-width apart and your feet spread wide apart.','Engage your core and slowly shift your weight forward, bringing your shoulders over your hands.','Bend your elbows and lower your body towards the ground, keeping your elbows close to your sides.','Pause for a moment at the bottom, then push through your hands to straighten your arms and lift your body back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'BL3GHeY'),
  ('db-1427', 'straight leg outer hip abductor', 'Legs', 'Body Weight', 'abductors', ARRAY['glutes','hamstrings']::text[], ARRAY['Lie on your side with your legs straight and stacked on top of each other.','Place your bottom arm under your head for support.','Engage your core and lift your top leg as high as possible without rotating your hips or leaning backward.','Pause for a moment at the top, then slowly lower your leg back down to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'mQ1tBXn'),
  ('db-0803', 'superman push-up', 'Chest', 'Body Weight', 'pectorals', ARRAY['core','shoulders']::text[], ARRAY['Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together.','Engage your core and lower your body towards the ground, keeping your elbows close to your sides.','As you lower your body, simultaneously lift your right arm and left leg off the ground, extending them straight out.','Pause for a moment at the top, then lower your arm and leg back down while pushing yourself back up to the starting position.','Repeat the movement, this time lifting your left arm and right leg.','Continue alternating sides for the desired number of repetitions.']::text[], '4GqRrAk'),
  ('db-0805', 'suspended abdominal fallout', 'Core', 'Body Weight', 'abs', ARRAY['obliques','hip flexors']::text[], ARRAY['Attach a suspension trainer to a high anchor point and adjust the straps to waist height.','Stand facing away from the anchor point and hold the handles with your arms extended in front of you.','Lean forward at the waist, keeping your body straight and your core engaged.','Lower your body as far as you can while maintaining control and tension in your abs.','Pause for a moment at the bottom, then slowly raise your body back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'X3TCNEU'),
  ('db-0806', 'suspended push-up', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Find a suspension trainer and adjust it to an appropriate height.','Stand facing away from the anchor point and hold the handles with an overhand grip.','Walk your feet forward, leaning your body forward until your weight is supported by the suspension trainer.','Keep your body straight from head to heels, engage your core, and lower your chest towards the handles.','Push through your chest and arms to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'IaGQCrC'),
  ('db-0807', 'suspended reverse crunch', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Hang from a pull-up bar with your arms fully extended and your palms facing away from you.','Engage your core and lift your knees up towards your chest, curling your pelvis towards your ribcage.','Pause for a moment at the top, then slowly lower your knees back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'R1WYG5D'),
  ('db-0808', 'suspended row', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','shoulders']::text[], ARRAY['Set up a suspension trainer at an appropriate height.','Stand facing the anchor point with your feet shoulder-width apart.','Hold the handles with an overhand grip, palms facing each other.','Lean back, keeping your body straight and your heels on the ground.','Pull your chest towards the handles, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly lower yourself back to the starting position.','Repeat for the desired number of repetitions.']::text[], '4OaumBr'),
  ('db-0809', 'suspended split squat', 'Legs', 'Body Weight', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Stand facing away from a suspension trainer with your feet shoulder-width apart.','Extend one leg forward and place the top of your foot in the foot cradle of the suspension trainer.','Bend your standing leg and lower your body down into a lunge position, keeping your chest up and your knee in line with your toes.','Push through your heel to return to the starting position.','Repeat for the desired number of repetitions, then switch legs.']::text[], 'QpXqiq8'),
  ('db-3433', 'swimmer kicks v. 2 (male)', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','quadriceps','calves']::text[], ARRAY['Lie face down on a mat with your arms extended overhead.','Engage your core and lift your chest and legs off the ground simultaneously.','Kick your legs up and down in a fluttering motion, as if you were swimming.','Continue kicking for the desired number of repetitions.','Lower your chest and legs back down to the starting position.']::text[], 'SP3hUez'),
  ('db-3318', 'swing 360', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['shoulders','core']::text[], ARRAY['Stand with your feet shoulder-width apart and knees slightly bent.','Hold your arms straight out in front of you, parallel to the ground.','Engage your core and swing your arms in a circular motion, rotating your torso as you do so.','Continue the circular motion, swinging your arms and rotating your torso for the desired number of repetitions.','Remember to breathe throughout the exercise.']::text[], 'tnaj0mT'),
  ('db-1753', 'three bench dip', 'Arms', 'Body Weight', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Sit on a bench with your hands gripping the edge, fingers pointing forward.','Slide your butt off the bench, supporting your weight with your hands.','Bend your elbows and lower your body until your upper arms are parallel to the ground.','Push yourself back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'DQ0cqkT'),
  ('db-2459', 'tire flip', 'Legs', 'Tire', 'glutes', ARRAY['hamstrings','quadriceps','core']::text[], ARRAY['Stand with your feet shoulder-width apart, facing the tire.','Bend your knees and hinge at the hips, lowering into a squat position.','Reach down and grab the bottom edge of the tire with both hands, fingers facing towards you.','Engage your glutes and leg muscles, and explosively drive through your legs to lift the tire off the ground.','As the tire flips over, use your upper body strength to guide it and maintain control.','Once the tire is fully flipped, quickly step back and reset your stance.','Repeat for the desired number of repetitions.']::text[], 'oZjMu1t'),
  ('db-0811', 'trap bar deadlift', 'Legs', 'Trap Bar', 'glutes', ARRAY['hamstrings','quadriceps','lower back']::text[], ARRAY['Stand with your feet shoulder-width apart and the trap bar on the ground in front of you.','Bend at the hips and knees to lower yourself down and grip the handles of the trap bar with an overhand grip.','Keep your back straight and chest up as you begin to lift the trap bar off the ground by extending your hips and knees.','As you lift, focus on driving through your heels and squeezing your glutes at the top of the movement.','Lower the trap bar back down to the ground by bending at the hips and knees, keeping your back straight throughout the movement.','Repeat for the desired number of repetitions.']::text[], 'jQGwmxN'),
  ('db-0814', 'triceps dip', 'Arms', 'Body Weight', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward.','Slide your butt off the bench, supporting your weight with your hands.','Bend your elbows and lower your body towards the ground, keeping your back close to the bench.','Pause for a moment at the bottom, then push yourself back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'X6C6i5Y'),
  ('db-0812', 'triceps dip (bench leg)', 'Arms', 'Body Weight', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Sit on the edge of a bench with your hands gripping the edge, fingers pointing forward.','Walk your feet forward, sliding your butt off the bench, and straighten your arms.','Bend your elbows and lower your body towards the ground, keeping your back close to the bench.','Push through your palms to straighten your arms and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'VuoerH0'),
  ('db-0813', 'triceps dip (between benches)', 'Arms', 'Body Weight', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Sit on a bench with your hands gripping the edge of the bench, fingers pointing forward.','Slide your butt off the bench, supporting your weight with your hands.','Bend your elbows and lower your body towards the ground, keeping your back close to the bench.','Pause for a moment at the bottom, then push yourself back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Wgbn9qo'),
  ('db-0815', 'triceps dips floor', 'Arms', 'Body Weight', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Sit on the edge of a chair or bench with your hands next to your hips, fingers pointing forward.','Slide your butt off the front of the chair with your legs extended in front of you.','Straighten your arms, keeping a little bend in your elbows to keep tension on your triceps and off your elbow joints.','Slowly bend your elbows to lower your body toward the floor until your elbows are at about a 90-degree angle.','Once you reach the bottom of the movement, press down into the chair to straighten your elbows, returning to the starting position.','Repeat for the desired number of repetitions.']::text[], '7aVz15j'),
  ('db-0816', 'triceps press', 'Arms', 'Body Weight', 'triceps', ARRAY['shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and your knees slightly bent.','Extend your arms straight out in front of you, parallel to the ground.','Bend your elbows and lower your body towards the ground, keeping your upper arms close to your sides.','Pause for a moment at the bottom, then push yourself back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'fSrPP6B'),
  ('db-0817', 'triceps stretch', 'Arms', 'Body Weight', 'triceps', ARRAY['shoulders']::text[], ARRAY['Stand or sit upright with your back straight.','Extend one arm overhead, bending it at the elbow.','Place your opposite hand on the bent elbow and gently pull it towards your head.','Hold the stretch for 15-30 seconds, feeling a gentle stretch in your triceps.','Release the stretch and repeat on the other arm.']::text[], 'uOV3Itw'),
  ('db-0871', 'tuck crunch', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands behind your head with your elbows pointing outwards.','Engaging your abs, lift your shoulder blades off the ground and bring your knees towards your chest, simultaneously curling your upper body towards your knees.','Pause for a moment at the top, then slowly lower your shoulder blades and extend your legs back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'BMMolZ3'),
  ('db-0818', 'twin handle parallel grip lat pulldown', 'Back', 'Cable', 'lats', ARRAY['biceps','rhomboids','rear deltoids']::text[], ARRAY['Adjust the seat height and position yourself facing the cable machine.','Grasp the handles with an overhand grip, hands shoulder-width apart.','Sit down and position your thighs under the thigh pads, keeping your feet flat on the floor.','Lean back slightly and keep your chest up, maintaining a neutral spine.','Pull the handles down towards your upper chest, squeezing your shoulder blades together.','Pause for a moment at the bottom of the movement, feeling the contraction in your lats.','Slowly release the handles and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'rkg41Fb'),
  ('db-1466', 'twist hip lift', 'Legs', 'Body Weight', 'glutes', ARRAY['obliques','hamstrings']::text[], ARRAY['Lie on your back with your knees bent and feet flat on the ground.','Place your hands by your sides for support.','Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders.','While keeping your hips lifted, twist your lower body to the right side, bringing your knees towards the ground.','Return to the starting position and repeat the twist to the left side.','Continue alternating twists for the desired number of repetitions.']::text[], 'AX1kB0o'),
  ('db-2802', 'twisted leg raise', 'Core', 'Body Weight', 'abs', ARRAY['obliques','hip flexors']::text[], ARRAY['Lie flat on your back with your legs extended and your arms by your sides.','Place your hands under your glutes for support.','Engage your abs and lift both legs off the ground, keeping them straight.','As you lift your legs, twist your hips to one side, bringing your legs towards your opposite shoulder.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat the movement, this time twisting your hips to the other side.','Continue alternating sides for the desired number of repetitions.']::text[], 'C0eCeEt'),
  ('db-2801', 'twisted leg raise (female)', 'Core', 'Body Weight', 'abs', ARRAY['obliques','hip flexors']::text[], ARRAY['Lie flat on your back with your legs extended and your arms by your sides.','Bend your knees and lift your legs off the ground, bringing them towards your chest.','As you lift your legs, twist your hips to one side, bringing your knees towards your opposite shoulder.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat the movement, this time twisting your hips to the other side.','Continue alternating sides for the desired number of repetitions.']::text[], 'yT9tk17'),
  ('db-3231', 'two toe touch (male)', 'Back', 'Body Weight', 'spine', ARRAY['hamstrings','glutes']::text[], ARRAY['Stand with your feet shoulder-width apart and your arms extended out to the sides.','Bend forward at the waist, keeping your back straight and your knees slightly bent.','Reach down towards your toes with both hands, keeping your legs straight.','Pause for a moment at the bottom, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'p195zsJ'),
  ('db-1365', 'upper back stretch', 'Back', 'Body Weight', 'upper back', ARRAY['shoulders']::text[], ARRAY['Stand up straight with your feet shoulder-width apart.','Extend your arms straight in front of you, parallel to the ground.','Interlace your fingers and rotate your palms away from your body.','Slowly raise your arms overhead, keeping them straight and parallel to each other.','As you raise your arms, squeeze your shoulder blades together.','Hold the stretch for 15-30 seconds, then release and repeat.']::text[], 'GSDioYu'),
  ('db-1366', 'upward facing dog', 'Back', 'Body Weight', 'spine', ARRAY['shoulders','chest']::text[], ARRAY['Lie face down on the floor with your legs extended behind you.','Place your hands on the floor next to your lower ribs, fingers pointing forward.','Press your hands firmly into the floor and straighten your arms, lifting your torso and thighs off the ground.','Roll your shoulders back and down, opening your chest and lifting your gaze towards the ceiling.','Hold this position for a few breaths, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '01qpYSe'),
  ('db-3420', 'v-sit on floor', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Sit on the floor with your legs extended in front of you.','Lean back slightly and lift your legs off the ground, keeping them straight.','Simultaneously, lift your upper body off the ground and reach your arms towards your legs.','Hold this position for a few seconds, then slowly lower your upper body and legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ZuXu4Eq'),
  ('db-0826', 'vertical leg raise (on parallel bars)', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Hang from the parallel bars with your arms fully extended and your body straight.','Engage your core and lift your legs up in front of you, keeping them straight.','Continue lifting until your legs are parallel to the ground or slightly higher.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ZNgOYQU'),
  ('db-2141', 'walk elliptical cross trainer', 'Other', 'Elliptical Machine', 'cardiovascular system', ARRAY['quadriceps','hamstrings','glutes','calves']::text[], ARRAY['Adjust the resistance level and incline of the elliptical machine to your desired settings.','Step onto the pedals of the machine and grip the handles lightly.','Begin by pushing down with your feet and pulling the handles towards your body.','Continue this motion, alternating between pushing and pulling, to simulate a walking or running motion.','Maintain a steady pace and keep your core engaged throughout the exercise.','Continue for the desired duration of your cardio workout.','Gradually decrease the intensity and speed of the machine before stepping off.']::text[], 'rjtuP6X'),
  ('db-3655', 'walking high knees lunge', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','glutes','calves']::text[], ARRAY['Stand with your feet hip-width apart.','Lift your right knee up towards your chest as high as you can while balancing on your left leg.','Step forward with your right foot and lower your body into a lunge position, bending both knees to a 90-degree angle.','Push off with your right foot and bring your left knee up towards your chest.','Step forward with your left foot and lower your body into a lunge position.','Continue alternating legs and lunging forward, keeping your core engaged and maintaining a steady pace.','Repeat for the desired number of repetitions.']::text[], 'J9zIWig'),
  ('db-1460', 'walking lunge', 'Legs', 'Body Weight', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart.','Take a step forward with your right leg, lowering your body into a lunge position.','Keep your torso upright and your front knee aligned with your ankle.','Push off with your right foot and bring your left foot forward, stepping into a lunge position with your left leg.','Continue alternating legs and walking forward, maintaining a controlled and steady pace.','Repeat for the desired number of repetitions.']::text[], 'IZVHb27'),
  ('db-3666', 'walking on incline treadmill', 'Other', 'Leverage Machine', 'cardiovascular system', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Adjust the incline level on the treadmill to your desired intensity.','Stand on the treadmill with your feet shoulder-width apart.','Start walking at a comfortable pace, ensuring that you maintain proper form.','Engage your core muscles and keep your back straight throughout the exercise.','Continue walking on the incline treadmill for the desired duration of your cardio workout.','Gradually decrease the incline and speed of the treadmill to cool down before stopping.']::text[], 'rjiM4L3'),
  ('db-2311', 'walking on stepmill', 'Other', 'Stepmill Machine', 'cardiovascular system', ARRAY['quadriceps','hamstrings','glutes','calves']::text[], ARRAY['Adjust the stepmill machine to a comfortable level.','Step onto the machine and place your hands on the handrails for support.','Start walking by placing one foot on a step and then the other, alternating between legs.','Maintain an upright posture and engage your core muscles.','Continue walking for the desired duration or distance.','Gradually increase the intensity or speed as you become more comfortable with the exercise.','Remember to cool down and stretch after completing the exercise.']::text[], 'j9Q5crt'),
  ('db-0830', 'weighted bench dip', 'Arms', 'Weighted', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Sit on a bench with your hands gripping the edge, fingers pointing forward.','Slide your butt off the bench, supporting your weight with your hands.','Lower your body by bending your elbows until your upper arms are parallel to the floor.','Push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'MU9HnE7'),
  ('db-2987', 'weighted close grip chin-up on dip cage', 'Back', 'Weighted', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Stand in front of the dip cage and grab the parallel bars with an underhand grip, hands shoulder-width apart.','Hang from the bars with your arms fully extended, feet off the ground, and body straight.','Engage your back muscles and pull your body up towards the bars, keeping your elbows close to your sides.','Continue pulling until your chin is above the bars, then pause for a moment.','Slowly lower your body back down to the starting position, fully extending your arms.','Repeat for the desired number of repetitions.']::text[], 'Gk1r408'),
  ('db-3643', 'weighted cossack squats (male)', 'Legs', 'Weighted', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet wider than shoulder-width apart and toes pointing slightly outward.','Hold a weight in front of your chest with both hands.','Shift your weight to one side and lower your body by bending the knee of the side you shifted towards, while keeping the other leg straight.','Go as low as you can while maintaining balance and keeping your chest up.','Push through the heel of the bent leg to return to the starting position.','Repeat on the other side, alternating between legs.']::text[], 'GWoKnIm'),
  ('db-0832', 'weighted crunch', 'Core', 'Weighted', 'abs', ARRAY['obliques']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Hold a weight plate or dumbbell on your chest.','Engage your abs and lift your upper body off the ground, curling forward until your shoulder blades are off the ground.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 's8nrDXF'),
  ('db-3670', 'weighted decline sit-up', 'Core', 'Weighted', 'abs', ARRAY['hip flexors','lower back']::text[], ARRAY['Lie flat on a decline bench with your feet secured under the foot pads.','Place your hands behind your head or across your chest.','Engage your abs and slowly lift your upper body off the bench, curling forward until your torso is perpendicular to the ground.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'EZeDVzO'),
  ('db-0833', 'weighted donkey calf raise', 'Legs', 'Weighted', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Stand on a raised platform with your toes on the edge and your heels hanging off.','Hold onto a stable object for support.','Raise your heels as high as possible by extending your ankles.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'LmaFNZS'),
  ('db-1310', 'weighted drop push up', 'Chest', 'Weighted', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together.','Lower your chest towards the ground, keeping your elbows close to your body.','Once your chest is just above the ground, explosively push yourself up, lifting your hands off the ground.','As you push up, quickly move your hands out to the sides and slightly forward, allowing your body to drop down towards the ground.','Catch yourself with your hands in the wider position and immediately lower your chest towards the ground again.','Repeat the push-up motion, dropping down and catching yourself with your hands in the narrower position.','Continue alternating between the wider and narrower hand positions for the desired number of repetitions.']::text[], 'PSlvNMs'),
  ('db-2135', 'weighted front plank', 'Core', 'Weighted', 'abs', ARRAY['shoulders','lower back']::text[], ARRAY['Start by lying face down on the floor.','Place your forearms on the ground, with your elbows directly under your shoulders.','Extend your legs straight out behind you, with your toes on the ground.','Engage your core and lift your body off the ground, balancing on your forearms and toes.','Keep your body in a straight line from your head to your heels.','Hold this position for the desired amount of time.','Lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'VBAWRPG'),
  ('db-0834', 'weighted front raise', 'Shoulders', 'Weighted', 'delts', ARRAY['biceps','forearms']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.','Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level.','Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'e4aFmFY'),
  ('db-0866', 'weighted hanging leg-hip raise', 'Core', 'Weighted', 'abs', ARRAY['hip flexors','lower back']::text[], ARRAY['Hang from a pull-up bar with your arms fully extended and your palms facing away from you.','Engage your core and lift your legs up in front of you, keeping them straight.','Continue lifting until your legs are parallel to the ground or slightly higher.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'QOA0FD0'),
  ('db-0835', 'weighted hyperextension (on stability ball)', 'Back', 'Weighted', 'spine', ARRAY['glutes','hamstrings']::text[], ARRAY['Position yourself face down on a stability ball with your hips resting on the ball and your feet against a wall for stability.','Place your hands behind your head or cross them over your chest.','Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '8urJS9b'),
  ('db-3641', 'weighted kneeling step with swing', 'Shoulders', 'Weighted', 'delts', ARRAY['triceps','core']::text[], ARRAY['Start in a kneeling position with your knees hip-width apart and your back straight.','Hold a weight in each hand, with your arms extended straight down in front of you.','Engage your core and swing the weights up and overhead, keeping your arms straight.','Lower the weights back down to the starting position and repeat for the desired number of repetitions.']::text[], '7uFJuXp'),
  ('db-3644', 'weighted lunge with swing', 'Legs', 'Weighted', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, holding a weight in each hand.','Take a step forward with your right foot, lowering your body into a lunge position.','As you lunge forward, swing the weights forward and upward, keeping your arms straight.','Push off with your right foot and return to the starting position, swinging the weights back down.','Repeat with your left foot and continue alternating legs for the desired number of repetitions.']::text[], '5WiFcYk'),
  ('db-3286', 'weighted muscle up', 'Back', 'Weighted', 'lats', ARRAY['biceps','triceps','shoulders','chest']::text[], ARRAY['Start by hanging from a pull-up bar with your palms facing away from you and your hands slightly wider than shoulder-width apart.','Engage your core and pull your body up towards the bar, leading with your chest.','As you reach the top of the movement, transition your grip so that your palms are facing towards you.','Continue pulling yourself up until your chest reaches the bar, then pause for a moment.','Slowly lower yourself back down to the starting position, maintaining control throughout the movement.','Repeat for the desired number of repetitions.']::text[], 'JsOV1SU'),
  ('db-3312', 'weighted muscle up (on bar)', 'Back', 'Weighted', 'lats', ARRAY['biceps','triceps','shoulders','forearms']::text[], ARRAY['Start by hanging from a pull-up bar with your palms facing away from you and your hands slightly wider than shoulder-width apart.','Engage your core and pull your shoulder blades down and back.','Bend your elbows and pull your chest towards the bar, keeping your body straight.','Once your chest reaches the bar, push down with your hands and drive your elbows back, lifting your body above the bar.','Pause at the top of the movement, then slowly lower yourself back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'MCkqdKE'),
  ('db-3290', 'weighted one hand pull up', 'Back', 'Weighted', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart.','Hang from the bar with your arm fully extended and your body straight.','Engage your core and pull your body up towards the bar by bending your elbow and squeezing your back muscles.','Continue pulling until your chin is above the bar.','Lower your body back down to the starting position with control.','Repeat for the desired number of repetitions.']::text[], 'fXfqg1E'),
  ('db-0840', 'weighted overhead crunch (on stability ball)', 'Core', 'Weighted', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.','Hold a weight plate or dumbbell with both hands and extend your arms overhead.','Engage your abs and slowly curl your torso forward, bringing your chest towards your knees.','Pause for a moment at the top, then slowly lower your torso back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'xmM75XG'),
  ('db-0841', 'weighted pull-up', 'Back', 'Weighted', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart.','Hang from the bar with your arms fully extended and your body straight.','Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.','Continue pulling until your chin is above the bar.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'HMzLjXx'),
  ('db-0844', 'weighted round arm', 'Shoulders', 'Weighted', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Raise your arms out to the sides, keeping a slight bend in your elbows.','Continue lifting your arms until they are parallel to the ground.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'VLYXo8S'),
  ('db-0846', 'weighted russian twist', 'Core', 'Weighted', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Sit on the ground with your knees bent and your feet flat on the floor.','Hold a weight or medicine ball with both hands in front of your chest.','Lean back slightly, keeping your back straight and your core engaged.','Slowly twist your torso to the right, bringing the weight or medicine ball towards the floor on your right side.','Pause for a moment, then twist your torso to the left, bringing the weight or medicine ball towards the floor on your left side.','Continue alternating sides for the desired number of repetitions.']::text[], 'fZFZ704'),
  ('db-0845', 'weighted russian twist (legs up)', 'Core', 'Weighted', 'abs', ARRAY['obliques','hip flexors']::text[], ARRAY['Sit on the ground with your knees bent and feet lifted off the ground, keeping your legs together.','Hold the weight with both hands in front of your chest, keeping your elbows slightly bent.','Lean back slightly to engage your core muscles.','Twist your torso to the right, bringing the weight towards the ground on your right side.','Pause for a moment, then twist your torso to the left, bringing the weight towards the ground on your left side.','Continue alternating sides for the desired number of repetitions.']::text[], 'WU9BLIs'),
  ('db-2371', 'weighted russian twist v. 2', 'Core', 'Weighted', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Sit on the ground with your knees bent and feet flat on the floor.','Hold the weight with both hands in front of your chest.','Lean back slightly to engage your core muscles.','Twist your torso to the right, bringing the weight towards the right side of your body.','Pause for a moment, then twist your torso to the left, bringing the weight towards the left side of your body.','Continue alternating sides for the desired number of repetitions.']::text[], 'YIUAtYf'),
  ('db-0847', 'weighted seated bicep curl (on stability ball)', 'Arms', 'Medicine Ball', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a stability ball with your feet flat on the ground and your back straight.','Hold a medicine ball with an underhand grip, palms facing up, and let your arms hang down by your sides.','Keeping your upper arms stationary, exhale and curl the medicine ball up towards your shoulders.','Pause for a moment at the top, squeezing your biceps.','Inhale and slowly lower the medicine ball back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'b4b6afT'),
  ('db-0849', 'weighted seated twist (on stability ball)', 'Core', 'Weighted', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.','Hold a weight plate or dumbbell with both hands close to your chest.','Engage your core and slowly rotate your torso to one side, keeping your hips stable.','Pause for a moment at the end of the rotation, then slowly return to the starting position.','Repeat the rotation to the other side.','Continue alternating sides for the desired number of repetitions.']::text[], 's34Y4LR'),
  ('db-0850', 'weighted side bend (on stability ball)', 'Core', 'Weighted', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Sit on a stability ball with your feet shoulder-width apart and flat on the ground.','Hold a weight in one hand and place your other hand on your hip.','Engage your core and slowly bend sideways towards the weighted side, keeping your back straight.','Pause for a moment at the bottom, then slowly return to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], '6bOA1Oi'),
  ('db-0851', 'weighted sissy squat', 'Legs', 'Weighted', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart and your toes pointing slightly outward.','Hold a weight in front of your chest with both hands, or place a barbell across your upper back.','Keeping your chest up and your core engaged, slowly lower your body down by bending at the knees and hips.','Continue lowering until your thighs are parallel to the ground or as low as you can comfortably go.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], '0lQnxMZ'),
  ('db-0852', 'weighted squat', 'Legs', 'Weighted', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, toes pointing slightly outward.','Hold a weight in front of your chest or on your shoulders.','Engage your core and keep your chest up as you lower your hips down and back, as if sitting into a chair.','Lower until your thighs are parallel to the ground, or as low as you can comfortably go.','Push through your heels to stand back up, squeezing your glutes at the top.','Repeat for the desired number of repetitions.']::text[], 'JZuApnB'),
  ('db-0853', 'weighted standing curl', 'Arms', 'Weighted', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.','Keep your elbows close to your torso and exhale as you curl the weights up to shoulder level.','Pause for a moment at the top, then inhale as you slowly lower the weights back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'M5Y7GPg'),
  ('db-0854', 'weighted standing hand squeeze', 'Arms', 'Weighted', 'forearms', ARRAY['biceps','triceps']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a weight in each hand.','Extend your arms straight in front of you, palms facing each other.','Squeeze your hands together as hard as you can, engaging your forearms.','Hold the squeeze for a few seconds, then release.','Repeat for the desired number of repetitions.']::text[], 'bjqbauy'),
  ('db-3313', 'weighted straight bar dip', 'Chest', 'Weighted', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Position yourself between parallel bars with your arms fully extended and your body straight.','Lower your body by bending your elbows until your upper arms are parallel to the ground.','Pause for a moment, then push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'Ff18ItA'),
  ('db-3642', 'weighted stretch lunge', 'Legs', 'Weighted', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart.','Take a step forward with your right foot, keeping your back straight.','Lower your body by bending your knees until your right thigh is parallel to the ground.','Push through your right heel to return to the starting position.','Repeat with your left leg.','Continue alternating legs for the desired number of repetitions.']::text[], '13VW2VO'),
  ('db-0856', 'weighted svend press', 'Chest', 'Weighted', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a weight plate in front of your chest with both hands.','Keep your elbows slightly bent and your palms facing each other.','Press the weight plate straight out in front of you, fully extending your arms.','Pause for a moment at the end of the movement, then slowly bring the weight plate back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'I1OBLnn'),
  ('db-1754', 'weighted three bench dips', 'Arms', 'Weighted', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Sit on the edge of a bench with your hands gripping the edge, fingers pointing forward.','Walk your feet forward, sliding your butt off the bench and supporting your weight with your arms.','Lower your body by bending your elbows, keeping your back close to the bench.','Pause for a moment at the bottom, then push yourself back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'gtO1ErP'),
  ('db-1755', 'weighted tricep dips', 'Arms', 'Weighted', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Sit on the edge of a bench or chair with your hands gripping the edge next to your hips.','Slide your butt off the front of the bench with your legs extended in front of you.','Keep your back close to the bench and your elbows slightly bent.','Lower your body by bending your elbows until your upper arms are parallel to the floor.','Push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'bZq4bwK'),
  ('db-1767', 'weighted triceps dip on high parallel bars', 'Arms', 'Weighted', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Position yourself between two parallel bars with your hands gripping the bars and your arms fully extended.','Bend your elbows and lower your body until your upper arms are parallel to the ground.','Pause for a moment, then push through your palms to straighten your arms and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'K1vlode'),
  ('db-0857', 'wheel rollerout', 'Core', 'Wheel Roller', 'abs', ARRAY['lower back']::text[], ARRAY['Kneel on the floor and place the wheel roller in front of you.','Place your hands on the handles of the wheel roller and extend your arms straight out in front of you.','Engage your core muscles and slowly roll the wheel forward, keeping your back straight and your abs tight.','Continue rolling forward until your body is fully extended and your arms are overhead.','Pause for a moment, then slowly roll the wheel back towards your knees, maintaining control and keeping your abs engaged.','Repeat for the desired number of repetitions.']::text[], 'NAgVB3t'),
  ('db-3637', 'wheel run', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Start in a plank position with your hands on the wheel and your body straight.','Engage your core and start rolling the wheel forward by extending your arms.','Continue rolling until your body is fully extended and your arms are overhead.','Reverse the movement by pulling the wheel back towards your body, using your core and arms.','Repeat for the desired number of repetitions.']::text[], 'km2Ljzj'),
  ('db-1429', 'wide grip pull-up', 'Back', 'Body Weight', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Hang from a pull-up bar with your palms facing away from you and your hands wider than shoulder-width apart.','Engage your core and squeeze your shoulder blades together.','Pull your body up towards the bar until your chin is above the bar.','Lower your body back down to the starting position with control.','Repeat for the desired number of repetitions.']::text[], 'Qqi7bko'),
  ('db-1367', 'wide grip rear pull-up', 'Back', 'Body Weight', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Grab the pull-up bar with a wide overhand grip, hands slightly wider than shoulder-width apart.','Hang from the bar with your arms fully extended and your body straight.','Engage your back muscles and pull your body up towards the bar, leading with your chest.','Continue pulling until your chin is above the bar.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'OYFhXVD'),
  ('db-1311', 'wide hand push up', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Start in a high plank position with your hands wider than shoulder-width apart.','Keep your body in a straight line from head to toe.','Lower your chest towards the ground by bending your elbows, keeping them close to your sides.','Push through your palms to extend your arms and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'JmMVpR3'),
  ('db-2363', 'wide-grip chest dip on high parallel bars', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Position yourself on the parallel bars with your arms fully extended and your body suspended in the air.','Lean forward slightly and lower your body by bending your elbows until your chest is just above the bars.','Pause for a moment, then push yourself back up to the starting position by straightening your arms.','Repeat for the desired number of repetitions.']::text[], 'O2K9Vb5'),
  ('db-0858', 'wind sprints', 'Core', 'Body Weight', 'abs', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Find an open space or a track to perform the exercise.','Start by standing with your feet shoulder-width apart.','Begin running as fast as you can, pumping your arms and driving your knees up.','Continue sprinting for a specific distance or time period.','Rest and repeat for the desired number of repetitions.']::text[], 'Qoujh3Q'),
  ('db-1604', 'world greatest stretch', 'Legs', 'Body Weight', 'hamstrings', ARRAY['glutes','quadriceps','calves']::text[], ARRAY['Start in a lunge position with your right foot forward and your left foot back.','Place your hands on the ground on either side of your right foot.','Lower your left knee to the ground and extend your right leg, keeping your right foot flat on the ground.','Rotate your torso to the right, reaching your right arm up towards the ceiling.','Hold this position for a few seconds, then return to the starting position.','Switch sides and repeat the stretch with your left foot forward.']::text[], 'DFGXwZr'),
  ('db-1428', 'wrist circles', 'Arms', 'Body Weight', 'forearms', ARRAY['hands','wrists']::text[], ARRAY['Extend your arms straight out in front of you.','Make a fist with both hands.','Rotate your wrists in a circular motion, keeping your arms still.','Continue the wrist circles for the desired number of repetitions.']::text[], '2zNKRUB'),
  ('db-0859', 'wrist rollerer', 'Arms', 'Weighted', 'forearms', ARRAY['biceps','triceps']::text[], ARRAY['Attach a weight to one end of a rope or bar.','Hold the other end of the rope or bar with both hands, palms facing down.','Stand with your feet shoulder-width apart and your arms fully extended in front of you.','Slowly roll the weight up towards your hands by flexing your wrists.','Pause for a moment at the top, then slowly lower the weight back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'bd5b860')
